namespace BlazorApp.Services;

/// <summary>
/// Background service that simulates new notifications arriving every ~7 seconds.
/// </summary>
public class NotificationGeneratorService : BackgroundService
{
    private readonly NotificationService _notificationService;

    public NotificationGeneratorService(NotificationService notificationService)
    {
        _notificationService = notificationService;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(7), stoppingToken);
            _notificationService.SimulateNewNotification();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@inject PersistentComponentState PersistentState
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in notifications.OrderByDescending(n => n.Id))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <small class="text-muted ms-2">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override void OnInitialized()
    {
        _persistingSubscription = PersistentState.RegisterOnPersisting(PersistNotifications);

        // Try to restore persisted state (avoids re-fetching on interactive activation)
        if (PersistentState.TryTakeFromJson<List<Notification>>("notifications", out var restored))
        {
            notifications = restored!;
        }
        else
        {
            // First render (static SSR) — load from service
            notifications = NotificationService.GetNotifications();
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Page is now interactive — start polling
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken).ConfigureAwait(false);

            if (cancellationToken.IsCancellationRequested)
                break;

            var lastId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
            var newItems = NotificationService.GetNotificationsSince(lastId);

            if (newItems.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    notifications.AddRange(newItems);
                    StateHasChanged();
                });
            }
        }
    }

    private Task PersistNotifications()
    {
        PersistentState.PersistAsJson("notifications", notifications);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

